# Role hierarchy map where higher keys have higher privileges
ROLE_LEVELS = {'admin': 4, 'manager': 3, 'editor': 2, 'viewer': 1}

def can_action(role, action):
    if role == 'admin':
        return True
    if role == 'manager':
        return action in ('view', 'edit', 'delete')
    if role == 'editor':
        return action in ('view', 'edit')
    return role == 'viewer' and action == 'view'

def check_permission(user, action, resource):
    # Check if user is the owner of the resource
    if resource.owner_id == user.user_id:
        return True
    # Delegate permission based on role hierarchy
    return can_action(user.role, action)
